import React, { useState, useEffect, useRef, useCallback } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
  },
  font: "'JetBrains Mono', monospace",
};

const STATES = [
  { name: 'Sunny',  short: 'S', color: '#fbbf24' },
  { name: 'Cloudy', short: 'C', color: '#94a3b8' },
  { name: 'Rainy',  short: 'R', color: '#38bdf8' },
];

const PRESETS = {
  balanced: { label: 'Balanced', matrix: [[0.6,0.3,0.1],[0.3,0.4,0.3],[0.1,0.3,0.6]] },
  sticky:   { label: 'Persistent', matrix: [[0.85,0.1,0.05],[0.1,0.8,0.1],[0.05,0.1,0.85]] },
  rainy:    { label: 'Mostly Rainy', matrix: [[0.4,0.4,0.2],[0.1,0.3,0.6],[0.05,0.15,0.8]] },
  chaotic:  { label: 'Chaotic', matrix: [[0.1,0.5,0.4],[0.4,0.1,0.5],[0.5,0.4,0.1]] },
};

const POS = [
  { x: 200, y: 55 },
  { x: 75,  y: 240 },
  { x: 325, y: 240 },
];

const R = 26;

function getArrowPoints(fi, ti, offset = 12) {
  const f = POS[fi], t = POS[ti];
  const dx = t.x - f.x, dy = t.y - f.y;
  const dist = Math.sqrt(dx*dx + dy*dy);
  const px = -dy/dist * offset, py = dx/dist * offset;
  const sx = f.x + (dx/dist)*R + px;
  const sy = f.y + (dy/dist)*R + py;
  const ex = t.x - (dx/dist)*(R+6) + px;
  const ey = t.y - (dy/dist)*(R+6) + py;
  const mx = (sx+ex)/2 + px*0.3;
  const my = (sy+ey)/2 + py*0.3;
  return { sx, sy, ex, ey, mx, my };
}

export default function App() {
  const [preset, setPreset] = useState('balanced');
  const [matrix, setMatrix] = useState(PRESETS.balanced.matrix);
  const [current, setCurrent] = useState(0);
  const [history, setHistory] = useState([0]);
  const [lastTransition, setLastTransition] = useState(null);
  const [randVal, setRandVal] = useState(null);
  const [counts, setCounts] = useState([1, 0, 0]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [stepCount, setStepCount] = useState(0);

  const stateRef = useRef({ current, matrix, history, counts, stepCount });
  useEffect(() => { stateRef.current = { current, matrix, history, counts, stepCount }; });

  const doStep = useCallback(() => {
    const { current: cur, matrix: mat, history: hist, counts: cts, stepCount: sc } = stateRef.current;
    const probs = mat[cur];
    const rand = Math.random();
    let cum = 0, next = probs.length - 1;
    for (let i = 0; i < probs.length; i++) {
      cum += probs[i];
      if (rand < cum) { next = i; break; }
    }
    setRandVal(rand);
    setLastTransition({ from: cur, to: next });
    setCurrent(next);
    setHistory(h => [...h.slice(-29), next]);
    setCounts(c => { const n=[...c]; n[next]++; return n; });
    setStepCount(s => s + 1);
  }, []);

  const intervalRef = useRef(null);

  const handlePlay = () => {
    if (isPlaying) {
      clearInterval(intervalRef.current);
      setIsPlaying(false);
    } else {
      setIsPlaying(true);
      intervalRef.current = setInterval(doStep, 650);
    }
  };

  const handleStep = () => { if (!isPlaying) doStep(); };

  const handleReset = () => {
    clearInterval(intervalRef.current);
    setIsPlaying(false);
    setCurrent(0);
    setHistory([0]);
    setLastTransition(null);
    setRandVal(null);
    setCounts([1, 0, 0]);
    setStepCount(0);
  };

  useEffect(() => () => clearInterval(intervalRef.current), []);

  const handlePreset = (key) => {
    clearInterval(intervalRef.current);
    setIsPlaying(false);
    setPreset(key);
    setMatrix(PRESETS[key].matrix);
    setCurrent(0);
    setHistory([0]);
    setLastTransition(null);
    setRandVal(null);
    setCounts([1, 0, 0]);
    setStepCount(0);
  };

  const totalVis = history.length;
  const cumBefore = (stateIdx) => {
    if (!lastTransition) return 0;
    return matrix[lastTransition.from].slice(0, stateIdx).reduce((a,b)=>a+b, 0);
  };

  const arrowColor = (fi, ti) => {
    if (lastTransition && lastTransition.from === fi && lastTransition.to === ti) return '#a3e635';
    if (fi === current) return STATES[fi].color + 'aa';
    return '#2a2a3a';
  };

  const arrowWidth = (fi, ti) => {
    if (lastTransition && lastTransition.from === fi && lastTransition.to === ti) return 2.5;
    if (fi === current) return 1.8;
    return 1.2;
  };

  const markerColor = (fi, ti) => {
    if (lastTransition && lastTransition.from === fi && lastTransition.to === ti) return 'lime';
    if (fi === current) return STATES[fi].color;
    return '#333';
  };

  return (
    <div style={{ minHeight:'100vh', background:theme.colors.background, fontFamily:theme.font, color:theme.colors.text, display:'flex', flexDirection:'column', alignItems:'center', padding:'16px' }}>
      <div style={{ width:'100%', maxWidth:'560px' }}>

        {/* Header */}
        <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'12px' }}>
          <div>
            <div style={{ fontSize:'18px', fontWeight:'700' }}>Markov Chain Walk</div>
            <div style={{ fontSize:'11px', color:theme.colors.textMuted, marginTop:'2px' }}>Weather changes day by day</div>
          </div>
          <div style={{ display:'flex', gap:'6px' }}>
            <button onClick={handleStep} disabled={isPlaying} style={{ background:theme.colors.surfaceAlt, border:`1px solid ${theme.colors.border}`, color:isPlaying?theme.colors.textMuted:theme.colors.text, padding:'7px 12px', borderRadius:'6px', cursor:isPlaying?'not-allowed':'pointer', fontSize:'11px', fontFamily:theme.font }}>Step</button>
            <button onClick={handlePlay} style={{ background:isPlaying?theme.colors.surfaceAlt:theme.colors.primary, border:`1px solid ${isPlaying?theme.colors.border:theme.colors.primary}`, color:'#fff', padding:'7px 12px', borderRadius:'6px', cursor:'pointer', fontSize:'11px', fontFamily:theme.font }}>{isPlaying?'Pause':'Auto'}</button>
            <button onClick={handleReset} style={{ background:'transparent', border:`1px solid ${theme.colors.border}`, color:theme.colors.textSecondary, padding:'7px 10px', borderRadius:'6px', cursor:'pointer', fontSize:'11px', fontFamily:theme.font }}>Reset</button>
          </div>
        </div>

        {/* Presets */}
        <div style={{ display:'flex', gap:'6px', marginBottom:'12px' }}>
          {Object.entries(PRESETS).map(([key, val]) => (
            <button key={key} onClick={() => handlePreset(key)} style={{ flex:1, padding:'5px 0', fontSize:'10px', borderRadius:'5px', cursor:'pointer', fontFamily:theme.font, background:preset===key?theme.colors.primary+'33':'transparent', border:`1px solid ${preset===key?theme.colors.primary:theme.colors.border}`, color:preset===key?theme.colors.primary:theme.colors.textMuted, transition:'all 0.2s' }}>
              {val.label}
            </button>
          ))}
        </div>

        {/* SVG State Graph */}
        <div style={{ background:theme.colors.surface, borderRadius:'12px', border:`1px solid ${theme.colors.border}`, padding:'8px', marginBottom:'10px' }}>
          <svg viewBox="0 0 400 300" width="100%" style={{ display:'block' }}>
            <defs>
              {STATES.flatMap((_, fi) => STATES.map((__, ti) => (
                fi !== ti ? (
                  <marker key={`m${fi}${ti}`} id={`arr${fi}${ti}`} markerWidth="7" markerHeight="7" refX="5" refY="3.5" orient="auto">
                    <path d="M0,0 L7,3.5 L0,7 z" fill={markerColor(fi,ti)} />
                  </marker>
                ) : null
              )))}
            </defs>

            {/* Self-loop arcs */}
            {STATES.map((_, i) => {
              const p = POS[i];
              const isCur = i === current;
              const isChosen = lastTransition && lastTransition.from === i && lastTransition.to === i;
              const col = isChosen ? '#a3e635' : isCur ? STATES[i].color+'99' : '#2a2a3a';
              const sw = isChosen ? 2.5 : isCur ? 1.8 : 1.2;
              let d, tx, ty;
              if (i === 0) {
                d = `M ${p.x-18} ${p.y-12} C ${p.x-40} ${p.y-65} ${p.x+40} ${p.y-65} ${p.x+18} ${p.y-12}`;
                tx = p.x; ty = p.y - 68;
              } else if (i === 1) {
                d = `M ${p.x-14} ${p.y-16} C ${p.x-65} ${p.y-35} ${p.x-65} ${p.y+20} ${p.x-16} ${p.y+14}`;
                tx = p.x - 72; ty = p.y;
              } else {
                d = `M ${p.x+16} ${p.y-14} C ${p.x+65} ${p.y-35} ${p.x+65} ${p.y+20} ${p.x+14} ${p.y+14}`;
                tx = p.x + 72; ty = p.y;
              }
              return (
                <g key={`self${i}`}>
                  <path d={d} fill="none" stroke={col} strokeWidth={sw} opacity={isCur?1:0.5} />
                  <text x={tx} y={ty} textAnchor="middle" dominantBaseline="middle" fill={isChosen?'#a3e635':isCur?STATES[i].color+'cc':'#444'} fontSize="10" fontFamily="monospace">
                    {matrix[i][i].toFixed(2)}
                  </text>
                </g>
              );
            })}

            {/* Arrows between different states */}
            {STATES.flatMap((_, fi) =>
              STATES.map((__, ti) => {
                if (fi === ti) return null;
                const { sx, sy, ex, ey, mx, my } = getArrowPoints(fi, ti);
                const col = arrowColor(fi, ti);
                const sw = arrowWidth(fi, ti);
                const isChosen = lastTransition && lastTransition.from===fi && lastTransition.to===ti;
                const isCurFrom = fi === current;
                return (
                  <g key={`${fi}-${ti}`}>
                    <line x1={sx} y1={sy} x2={ex} y2={ey}
                      stroke={col} strokeWidth={sw}
                      opacity={isCurFrom||isChosen ? 1 : 0.35}
                      markerEnd={`url(#arr${fi}${ti})`}
                    />
                    <text x={mx} y={my} textAnchor="middle" dominantBaseline="middle"
                      fill={isChosen?'#a3e635':isCurFrom?STATES[fi].color+'cc':'#444'}
                      fontSize="9" fontFamily="monospace">
                      {matrix[fi][ti].toFixed(2)}
                    </text>
                  </g>
                );
              })
            )}

            {/* State circles */}
            {STATES.map((state, i) => {
              const p = POS[i];
              const isActive = current === i;
              return (
                <g key={i}>
                  {isActive && <circle cx={p.x} cy={p.y} r={38} fill={state.color} opacity={0.12} />}
                  <circle cx={p.x} cy={p.y} r={R}
                    fill={isActive ? state.color+'22' : theme.colors.surfaceAlt}
                    stroke={isActive ? state.color : '#333'}
                    strokeWidth={isActive ? 2.5 : 1.5}
                  />
                  <text x={p.x} y={p.y-5} textAnchor="middle" dominantBaseline="middle"
                    fill={isActive ? state.color : theme.colors.textSecondary}
                    fontSize="13" fontWeight="700" fontFamily="monospace">
                    {state.short}
                  </text>
                  <text x={p.x} y={p.y+11} textAnchor="middle" dominantBaseline="middle"
                    fill={isActive ? state.color+'cc' : theme.colors.textMuted}
                    fontSize="8" fontFamily="monospace">
                    {state.name}
                  </text>
                </g>
              );
            })}
          </svg>
        </div>

        {/* Probability bars for current state */}
        <div style={{ background:theme.colors.surface, borderRadius:'10px', border:`1px solid ${theme.colors.border}`, padding:'12px 14px', marginBottom:'10px' }}>
          <div style={{ fontSize:'10px', color:theme.colors.textMuted, marginBottom:'9px' }}>
            From <span style={{ color:STATES[current].color, fontWeight:'700' }}>{STATES[current].name}</span> - which state comes next?
            {randVal !== null && lastTransition && (
              <span style={{ color:'#a3e635', marginLeft:'8px' }}>rolled {randVal.toFixed(3)}</span>
            )}
          </div>
          {STATES.map((state, j) => {
            const prob = matrix[current][j];
            const isChosen = lastTransition && lastTransition.from === current && lastTransition.to === j;
            const cBefore = cumBefore(j);
            const cAfter = cBefore + prob;
            return (
              <div key={j} style={{ display:'flex', alignItems:'center', gap:'8px', marginBottom:'5px' }}>
                <div style={{ width:'44px', fontSize:'10px', color:state.color, fontWeight:'600' }}>{state.name}</div>
                <div style={{ flex:1, background:'#1a1a1a', borderRadius:'3px', height:'20px', position:'relative', overflow:'hidden' }}>
                  <div style={{ position:'absolute', left:`${cBefore*100}%`, width:`${prob*100}%`, height:'100%', background: isChosen ? '#a3e635' : state.color+'55', borderRadius:'2px', transition:'all 0.3s ease' }} />
                  {randVal !== null && lastTransition && lastTransition.from === current && (
                    <div style={{ position:'absolute', left:`${randVal*100}%`, top:0, bottom:0, width:'2px', background:'rgba(255,255,255,0.8)', transition:'left 0.3s ease' }} />
                  )}
                </div>
                <div style={{ width:'32px', fontSize:'10px', color:isChosen?'#a3e635':theme.colors.textMuted, fontWeight:isChosen?'700':'400', textAlign:'right' }}>
                  {Math.round(prob*100)}%
                </div>
                {isChosen && <div style={{ fontSize:'10px', color:'#a3e635', width:'10px' }}>*</div>}
                {!isChosen && <div style={{ width:'10px' }} />}
              </div>
            );
          })}
        </div>

        {/* History trail */}
        <div style={{ background:theme.colors.surface, borderRadius:'10px', border:`1px solid ${theme.colors.border}`, padding:'10px 14px', marginBottom:'10px' }}>
          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'7px' }}>
            <div style={{ fontSize:'10px', color:theme.colors.textMuted }}>State history</div>
            <div style={{ fontSize:'10px', color:theme.colors.textMuted }}>{stepCount} steps taken</div>
          </div>
          <div style={{ display:'flex', gap:'3px', flexWrap:'wrap' }}>
            {history.slice(-30).map((s, i, arr) => (
              <div key={i} style={{
                width:'17px', height:'17px', borderRadius:'3px',
                background: STATES[s].color + (i===arr.length-1?'ff':'66'),
                display:'flex', alignItems:'center', justifyContent:'center',
                fontSize:'8px', color:'#000000cc', fontWeight:'800',
                border: i===arr.length-1 ? `2px solid ${STATES[s].color}` : 'none',
              }}>
                {STATES[s].short}
              </div>
            ))}
          </div>

          {stepCount >= 15 && (
            <div style={{ marginTop:'10px', paddingTop:'8px', borderTop:`1px solid ${theme.colors.border}` }}>
              <div style={{ fontSize:'10px', color:theme.colors.textMuted, marginBottom:'5px' }}>Observed frequency (converging to steady state):</div>
              <div style={{ display:'flex', gap:'0px' }}>
                {STATES.map((state, i) => {
                  const pct = counts[i] / totalVis;
                  return (
                    <div key={i} style={{ flex: pct, background: state.color+'44', borderRight:`1px solid #0a0a0a`, height:'18px', display:'flex', alignItems:'center', justifyContent:'center', minWidth: pct > 0 ? '20px' : '0', transition:'flex 0.4s ease', overflow:'hidden' }}>
                      <span style={{ fontSize:'9px', color:state.color, fontWeight:'700', whiteSpace:'nowrap' }}>
                        {Math.round(pct*100)}%
                      </span>
                    </div>
                  );
                })}
              </div>
            </div>
          )}
        </div>

        {/* Insight */}
        <div style={{ background:theme.colors.surfaceAlt, borderRadius:'8px', padding:'9px 12px', fontSize:'11px', color:theme.colors.textSecondary, borderLeft:`3px solid ${theme.colors.primary}`, lineHeight:'1.5' }}>
          {!lastTransition && stepCount === 0 && (
            <span><span style={{ color:theme.colors.primary, fontWeight:'700' }}>Key: </span>Press Step. Each day, a random number is rolled and lands in one state's segment on the probability bar. Only the CURRENT state matters - not yesterday's weather. That's the Markov property.</span>
          )}
          {lastTransition && randVal !== null && (
            <span>
              Rolled <span style={{ color:'#a3e635', fontWeight:'700' }}>{randVal.toFixed(3)}</span> from {STATES[lastTransition.from].name} - landed in {STATES[lastTransition.to].name}'s range ({cumBefore(lastTransition.to).toFixed(2)}-{(cumBefore(lastTransition.to)+matrix[lastTransition.from][lastTransition.to]).toFixed(2)}). Tomorrow's forecast depends only on today, not on past days.
            </span>
          )}
          {!lastTransition && stepCount > 0 && (
            <span><span style={{ color:theme.colors.primary, fontWeight:'700' }}>Insight: </span>After many steps, frequencies converge to the steady-state distribution - the same distribution no matter which state you started from.</span>
          )}
        </div>

      </div>
    </div>
  );
}
